#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---int check(string &n, string &c){    ll count=0;    int i=c.length()-1;    for(int j=n.length()-1;j>=0;j--){        if(n[j]==c[i]){            i--;            if(i<0){                break;            }        }        else{            count++;        }    }    if(i>=0){        return INT_MAX;    }    else{        return count;    }    }void solve() {    string n;    cin >> n;    vector<string> candidates={"00","25","50","75"};    int ans=INT_MAX;    for(auto &c:candidates){        ans=min(ans,check(n,c));    }    cout<<ans<<endl;            } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}